form:Form.form:Scripts:
		function ValidaStock()
{
	var cantDisp;  
  var nSQL = GetProxy().SQLService();
  var param = "<PARAM oi_uniforme=\""+Ctrl('oi_uniforme').GetXValue() + "\"/>"; 

  cantDisp = nSQL.GetOBJ(Ctrl("main").getResource("QRY_EXISTENCIAS"), param);	

  if(parseInt(Ctrl('e_cantidad').GetXValue(),10) > parseInt(cantDisp.stock,10)) 
		return confirm("No hay stock disponible a la fecha. Desea continuar de todos modos?");		  
  return true;
}
